const logger = createLogger('VectorIndex');

function isExpectedMissingVecMemoriesTable(error: unknown): boolean {
  const message = get_error_message(error).toLowerCase();
  return message.includes('no such table') && message.includes('vec_memories');
}

function activeVectorTableExists(database: Database.Database, tableName: string): boolean {
  try {
    const row = database.prepare(`
      SELECT 1 AS found
      FROM ${activeVectorSource('sqlite_master')}
      WHERE type = 'table' AND name = ?
      LIMIT 1
    `).get(tableName) as { found?: number } | undefined;
    return row?.found === 1;
  } catch (_error: unknown) {
    return false;
  }
}

function activeDimVectorSource(database: Database.Database): string | null {
  const active = getActiveEmbedder(database);
  if (active.name === DEFAULT_ACTIVE_EMBEDDER.name) {
    return null;
  }
  const tableName = vecTableNameForDim(active.dim);
  return activeVectorTableExists(database, tableName) ? activeVectorSource(tableName) : null;
}

function writeActiveVectorPayload(database: Database.Database, id: bigint, embeddingBuffer: Buffer): void {
  database.prepare(`DELETE FROM ${activeVectorSource('vec_memories')} WHERE rowid = ?`).run(id);
  database.prepare(`
    INSERT INTO ${activeVectorSource('vec_memories')} (rowid, embedding) VALUES (?, ?)
  `).run(id, embeddingBuffer);

  const dimSource = activeDimVectorSource(database);
  if (dimSource) {
    database.prepare(`INSERT OR REPLACE INTO ${dimSource} (id, vec) VALUES (?, ?)`).run(id, embeddingBuffer);
  }
}

function deleteActiveVectorPayload(database: Database.Database, id: bigint): void {
  database.prepare(`DELETE FROM ${activeVectorSource('vec_memories')} WHERE rowid = ?`).run(id);
  const dimSource = activeDimVectorSource(database);
  if (dimSource) {
    database.prepare(`DELETE FROM ${dimSource} WHERE id = ?`).run(id);
  }
}

function invalidateGraphCaches(database: Database.Database): void {
  // Bump the generation FIRST so every cache key that includes it (e.g.
  // memory_search with causal boost) goes stale before the per-db caches clear;
  // without this, memory-delete sweeps served stale causal-boosted search results.
  bumpCausalEdgesGeneration();

  try {
    clearDegreeCacheForDb(database);
  } catch (_error: unknown) {
    // Degree cache invalidation is best-effort for legacy mutation paths.
  }

  try {
    clearGraphSignalsCache();
  } catch (_error: unknown) {
    // Graph signal cache invalidation is best-effort for legacy mutation paths.
  }
}

function tryRecordTierDowngradeAudit(
  database: Database.Database,
  params: {
    memoryId: number;
    specFolder: string | null | undefined;
    anchorId: string | null | undefined;
    filePath: string | null | undefined;
    canonicalFilePath: string | null | undefined;
    requestedTier?: string | null | undefined;
    previousTier?: string | null | undefined;
    nextTier: string;
    source: string;
  },
): void {
  try {
    recordTierDowngradeAudit(database, {
      memoryId: params.memoryId,
      logicalKey: buildGovernanceLogicalKey(
        params.specFolder,
        params.canonicalFilePath || params.filePath,
        params.anchorId,
      ),
      requestedTier: params.requestedTier ?? undefined,
      previousTier: params.previousTier ?? undefined,
      nextTier: params.nextTier,
      source: params.source,
      filePath: params.filePath ?? null,
      canonicalFilePath: params.canonicalFilePath ?? null,
    });
  } catch (error: unknown) {
    logger.warn('Failed to record governance audit for tier downgrade', {
      memoryId: params.memoryId,
      source: params.source,
      message: get_error_message(error),
    });
  }
}

function deleteAncillaryMemoryRows(database: Database.Database, id: number): void {
  const ancillaryTables = [
    'DELETE FROM degree_snapshots WHERE memory_id = ?',
    'DELETE FROM community_assignments WHERE memory_id = ?',
    'DELETE FROM memory_summaries WHERE memory_id = ?',
    'DELETE FROM memory_entities WHERE memory_id = ?',
    'DELETE FROM memory_lineage WHERE memory_id = ?',
  ];

  for (const sql of ancillaryTables) {
    try {
      const paramCount = (sql.match(/\?/g) || []).length;
      if (paramCount === 2) {
        database.prepare(sql).run(id, id);
      } else {
        database.prepare(sql).run(id);
      }
    } catch (_error: unknown) {
      // Best-effort for legacy databases that may not have these tables yet.
    }
  }

  // Clean active_memory_projection rows referencing this memory.
  try {
    database.prepare('DELETE FROM active_memory_projection WHERE active_memory_id = ?').run(id);
  } catch (_error: unknown) {
    // Best-effort for legacy databases that may not have projection tables yet.
  }

  try {
    const result = sweepCausalEdges(database, {
      memoryIds: [id, String(id)],
      reason: 'memory row mutation cleanup',
      command: 'vector-index-mutations.deleteAncillaryMemoryRows',
      restoreContext: { memoryId: id },
      invalidateCaches: false,
    });
    if (result.deleted > 0) {
      invalidateGraphCaches(database);
    }
  } catch (error: unknown) {
    // Tolerate only legacy databases that predate the causal-edge tables. Scope
    // the match to those table names so an unrelated missing-table error still
    // propagates and rolls back the surrounding delete instead of committing a
    // hard delete without its tombstone audit row.
    const message = error instanceof Error ? error.message : String(error);
    if (!/no such table:\s*causal_edge/i.test(message)) {
      throw error;
    }
  }
}

function upsert_active_projection(
  database: ReturnType<typeof initialize_db>,
  specFolder: string,
  canonicalFilePath: string,
  anchorId: string | null,
  memoryId: number,
  updatedAt: string,
  scope: NormalizedMemoryScope,
): void {
  const logicalKey = buildMemoryLogicalKey({
    specFolder,
    filePath: canonicalFilePath,
    canonicalFilePath,
    anchorId,
    ...scope,
  });
  // Evict any stale projection row that maps a *different* logical_key to the
  // same active_memory_id — prevents UNIQUE constraint violation on re-index
  // when the logical_key changes (e.g. anchor or path normalization drift).
  database.prepare(
    'DELETE FROM active_memory_projection WHERE active_memory_id = ? AND logical_key != ?',
  ).run(memoryId, logicalKey);
  database.prepare(`
    INSERT INTO active_memory_projection (logical_key, root_memory_id, active_memory_id, updated_at)
    VALUES (?, ?, ?, ?)
    ON CONFLICT(logical_key) DO UPDATE SET
      root_memory_id = excluded.root_memory_id,
      active_memory_id = excluded.active_memory_id,
      updated_at = excluded.updated_at
  `).run(logicalKey, memoryId, memoryId, updatedAt);
}

// These mutation-local extensions are intentional until the shared query/store
// contract adopts appendOnly and canonicalFilePath semantics.
type IndexMemoryParams = Readonly<SharedIndexMemoryParams> & {
  readonly appendOnly?: boolean;
};
type IndexMemoryDeferredParams = Omit<IndexMemoryParams, 'embedding'> & {
  readonly failureReason?: string | null;
};
type UpdateMemoryParams = Readonly<SharedUpdateMemoryParams> & {
  readonly canonicalFilePath?: string;
  // Set when the row's document now lives at a new on-disk location, so a
  // moved file repoints its existing row instead of leaving a stale path.
  readonly filePath?: string;
};

type NormalizedMemoryScope = {
  tenant_id: string | null;
  user_id: string | null;
  agent_id: string | null;
  session_id: string | null;
};

function normalizeMemoryScope(scope?: MemoryScopeParams): NormalizedMemoryScope {
  return {
    tenant_id: normalizeScopeValue(scope?.tenantId),
    user_id: normalizeScopeValue(scope?.userId),
    agent_id: normalizeScopeValue(scope?.agentId),
    session_id: normalizeScopeValue(scope?.sessionId),
  };
}

/**
 * Indexes a memory with an embedding payload.
 * @param params - The memory values to index.
 * @returns The indexed memory identifier.
 * @throws {VectorIndexError} When embedding validation fails or the mutation cannot be applied.
 * @example
 * ```ts
 * const id = index_memory({
 *   specFolder: 'specs/001-demo',
 *   filePath: 'spec.md',
 *   embedding,
 * });
 * ```
 */
export function index_memory(
  params: IndexMemoryParams,
  database: Database.Database = initialize_db(),
): number {
  const {
    specFolder,
    filePath,
    parentId = null,
    anchorId = null,
    title = null,
    triggerPhrases = [],
    importanceWeight = 0.5,
    embedding,
    encodingIntent,
    documentType = 'memory',
    specLevel = null,
    contentText = null,
    qualityScore = 0,
    qualityFlags = [],
    appendOnly = false,
  } = params;
  const scope = normalizeMemoryScope(params.scope);

  if (!embedding) {
    throw new VectorIndexError('Embedding is required', VectorIndexErrorCode.EMBEDDING_VALIDATION);
  }

  const expected_dim = get_embedding_dim();
  if (embedding.length !== expected_dim) {
    console.warn(`[vector-index] Embedding dimension mismatch: expected ${expected_dim}, got ${embedding.length}`);
    throw new VectorIndexError(
      `Embedding must be ${expected_dim} dimensions, got ${embedding.length}`,
      VectorIndexErrorCode.EMBEDDING_VALIDATION,
    );
  }

  const now = new Date().toISOString();
  const triggers_json = JSON.stringify(triggerPhrases);
  const embedding_buffer = to_embedding_buffer(embedding);
  const canonicalFilePath = getCanonicalPathKey(filePath);

  const stmts = init_prepared_statements(database);
  const existing = appendOnly
    ? null
    : stmts.get_by_folder_and_path.get(
        specFolder,
        canonicalFilePath,
        filePath,
        canonicalFilePath,
        filePath,
        anchorId,
        scope.tenant_id,
        scope.user_id,
        scope.agent_id,
        scope.session_id,
      );

  if (existing && !appendOnly) {
    return update_memory({
      id: existing.id,
      title: title ?? undefined,
      triggerPhrases,
      importanceWeight,
      embedding,
      encodingIntent,
      documentType,
      specLevel,
      contentText,
      qualityScore,
      qualityFlags,
      canonicalFilePath,
      filePath,
    }, database);
  }

  const sqlite_vec = get_sqlite_vec_available();

  const index_memory_tx = database.transaction(() => {
    const embedding_status = sqlite_vec ? 'success' : 'pending';

    const result = database.prepare(`
      INSERT INTO memory_index (
        spec_folder, file_path, canonical_file_path, anchor_id, title, trigger_phrases,
        importance_weight, created_at, updated_at, embedding_model,
        embedding_generated_at, embedding_status, encoding_intent, document_type, spec_level,
        content_text, quality_score, quality_flags, parent_id,
        tenant_id, user_id, agent_id, session_id
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      specFolder, filePath, canonicalFilePath, anchorId, title, triggers_json,
      importanceWeight, now, now, embeddingsProvider.getModelName(), now, embedding_status,
      encodingIntent ?? 'document', documentType, specLevel, contentText, qualityScore, JSON.stringify(qualityFlags), parentId,
      scope.tenant_id, scope.user_id, scope.agent_id, scope.session_id

